<template>
  <div class="container">
    <div v-for="(title, index) in titles" :key="index" class="custom-cell" @click="gotoMarkdown(title)">
      <div class="title">{{ title }}</div>
      <div class="label">更新时间：{{ updateTimes[index] }}</div>
    </div>
    <van-tabbar v-model="active">
      <van-tabbar-item icon="home-o" :to="{ name: 'frontView' }">杂七杂八的踩坑</van-tabbar-item>
      <van-tabbar-item icon="desktop-o" :to="{ name: 'backDevView' }">后端开发</van-tabbar-item>
      <van-tabbar-item icon="edit" :to="{ name: 'AlgorithmView' }">算法</van-tabbar-item>
      <van-tabbar-item icon="manager-o" :to="{ name: 'mineView' }">我的</van-tabbar-item>
    </van-tabbar>
  </div>
</template>
  
<script>
import axios from 'axios';

export default {
  data() {
    return {
      titles: [],
      updateTimes: [],
      active: 0
    };
  },
  created() {
    axios.get("https://gitee.com/api/v5/repos/Lysssyo/DataofPersonalPage/contents/Index.md?access_token=92843fa7206d85719b3f23d70f1a0a9a&ref=FrontView")
      .then(resp => {
        const indexData = resp.data.content;
        console.log("Index Data:", indexData);
        const decodedindexData = atob(indexData);
        const utf8DecodedIndexData = decodeURIComponent(escape(decodedindexData));
        console.log("Index Data:", utf8DecodedIndexData);

        const titles = utf8DecodedIndexData.match(/Tittle：(.*?)\n/g).map(match => match.replace("Tittle：", "").trim());
        const updateTimes = utf8DecodedIndexData.match(/UpdateTime：(.*?)\n/g).map(match => match.replace("UpdateTime：", "").trim());

        this.titles = titles;
        this.updateTimes = updateTimes;

        console.log("Titles:", this.titles);
        console.log("Update Times:", this.updateTimes);
      })
      .catch(error => {
        console.error('Error fetching data:', error);
      });
  },
  methods: {
    //判定字符串是否为中文
    isChinese(str) {
      // 匹配中文字符的正则表达式
      var reg = new RegExp("[\\u4E00-\\u9FFF]+", "g");
      // 如果匹配到中文字符则返回 true，否则返回 false
      return reg.test(str);
    },
    gotoMarkdown(unCodeTittle) {
      console.log("进入gotoMarkdown方法");
      let tittle =unCodeTittle;
      if (this.isChinese(unCodeTittle)) {
        //如果markdown文件的名字为中文，需要进行编码
       tittle = encodeURIComponent(unCodeTittle);
      }
      const BranchParam = "FrontView"; // 另一个参数的值
      console.log("传递过去的参数：" + tittle);

      // 跳转到 Markdown 页面，传递多个参数
      this.$router.push({
        name: 'markdownView',
        params: {
          tittle,
          BranchParam
        }
      });
    }
  }

};
</script>
  
<style scoped>
.container {
  border-top: 1px solid #000;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: flex-start;
  height: 100%;
  padding-top: 10px;
  padding-bottom: 140px;
}

.custom-cell {
  width: 90%;
  margin: 3px;
  border-radius: 10px;
  padding: 10px;
  background-color: #ffffff;
  box-shadow: 0px 2px 4px rgba(0, 0, 0, 0.1);
  cursor: pointer;
}

.title {
  font-weight: bold;
  font-size: 16px;
  color: #333;
  padding-bottom: 3px;
}

.label {
  font-size: 14px;
  color: #666;
}
</style>
  